"""In-memory data models."""
from datetime import datetime, timezone
import re

_users = {}
_posts = {}
_next_user_id = 1
_next_post_id = 1

def validate_email(email):
    return bool(re.match(r'^[\w.+-]+@[\w-]+\.[\w.-]+$', email))

def create_user(name, email):
    global _next_user_id
    if not name or not name.strip():
        return None, 'Name cannot be empty'
    if not validate_email(email):
        return None, 'Invalid email format'
    for u in _users.values():
        if u['email'] == email:
            return None, 'duplicate_email'
    uid = _next_user_id
    _next_user_id += 1
    user = {
        'id': uid,
        'name': name.strip(),
        'email': email.strip(),
        'created_at': datetime.now(timezone.utc).strftime('%Y-%m-%d %H:%M:%S')  # SPEC: should be ISO-8601 with Z
    }
    _users[uid] = user
    return user, None

def get_user(user_id):
    return _users.get(user_id)

def update_user(user_id, **fields):
    user = _users.get(user_id)
    if not user:
        return None, 'not_found'
    if 'name' in fields:
        if not fields['name'] or not fields['name'].strip():
            return None, 'Name cannot be empty'
        user['name'] = fields['name'].strip()
    if 'email' in fields:
        if not validate_email(fields['email']):
            return None, 'Invalid email format'
        user['email'] = fields['email'].strip()
    return user, None

def delete_user(user_id):
    if user_id in _users:
        del _users[user_id]
        return True
    return False

def list_users(offset=0, limit=20, sort_by='created_at'):
    users = list(_users.values())
    reverse = sort_by == 'created_at'  # SPEC: default created_at descending
    users.sort(key=lambda u: u.get(sort_by, ''), reverse=reverse)
    total = len(users)
    return users[offset:offset+limit], total

def create_post(user_id, title, body, tags=None):
    global _next_post_id
    if user_id not in _users:
        return None, 'user_not_found'
    if not title or not title.strip():
        return None, 'Title cannot be empty'
    pid = _next_post_id
    _next_post_id += 1
    post = {
        'id': pid,
        'user_id': user_id,
        'title': title.strip(),
        'body': body,
        'tags': tags or [],
        'created_at': datetime.now(timezone.utc).strftime('%Y-%m-%d %H:%M:%S')  # SPEC: should be ISO-8601
    }
    _posts[pid] = post
    return post, None

def get_user_posts(user_id, offset=0, limit=20, tag=None):
    if user_id not in _users:
        return None, 'user_not_found'
    posts = [p for p in _posts.values() if p['user_id'] == user_id]
    if tag:
        posts = [p for p in posts if tag in p.get('tags', [])]
    total = len(posts)
    return posts[offset:offset+limit], total, None

def delete_post(post_id):
    if post_id in _posts:
        del _posts[post_id]
        return True
    return False

def reset_db():
    global _next_user_id, _next_post_id
    _users.clear()
    _posts.clear()
    _next_user_id = 1
    _next_post_id = 1

