"""User endpoint handlers."""
from flask import Blueprint, request, jsonify
from models import create_user, get_user, update_user, delete_user, list_users

users_bp = Blueprint('users', __name__)

@users_bp.route('/users', methods=['POST'])
def create_user_endpoint():
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Invalid JSON'}), 400  # SPEC: wrong format
    user, err = create_user(data.get('name', ''), data.get('email', ''))
    if err:
        if 'duplicate' in err.lower():
            return jsonify({'error': err}), 409  # SPEC: missing error code
        return jsonify({'error': err}), 400  # SPEC: missing error code
    return jsonify(user), 200  # SPEC: should be 201 + Location header

@users_bp.route('/users/<int:user_id>', methods=['GET'])
def get_user_endpoint(user_id):
    user = get_user(user_id)
    if not user:
        return jsonify({'message': 'User not found'}), 404  # SPEC: wrong format
    return jsonify(user), 200

@users_bp.route('/users/<int:user_id>', methods=['PATCH'])
def update_user_endpoint(user_id):
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Invalid JSON', 'code': 'INVALID_INPUT'}), 400
    user, err = update_user(user_id, **data)
    if err == 'not_found':
        return jsonify({'message': 'Not found'}), 404  # SPEC: wrong format
    if err:
        return jsonify({'error': err}), 400  # SPEC: missing code
    return jsonify(user), 200

@users_bp.route('/users/<int:user_id>', methods=['DELETE'])
def delete_user_endpoint(user_id):
    if delete_user(user_id):
        return jsonify({'message': 'Deleted'}), 200  # SPEC: should be 204 empty
    return jsonify({'error': 'User not found'}), 404  # SPEC: missing code

@users_bp.route('/users', methods=['GET'])
def list_users_endpoint():
    offset = request.args.get('offset', 0, type=int)
    limit = request.args.get('limit', 20, type=int)
    limit = min(limit, 100)  # SPEC: max 100
    sort_by = request.args.get('sort_by', 'created_at')
    users, total = list_users(offset, limit, sort_by)
    return jsonify({'users': users}), 200  # SPEC: missing total, offset, limit fields

